size(7cm);
pair A=(2,7), B=(0,0), C=(6,-0.5), X=(A+B)/2, Y=6/10*A+4/10*C;
pair[] dots={A,B,C,X,Y};
dot(dots);
draw(A--B--C--cycle);
draw(X--Y);
label("$A$",A,N);
label("$B$",B,SW);
label("$C$",C,SE);
label("$X$",X,W);
label("$Y$",Y,E);
draw(C--X);
[/asy]

